206→  const handleDoubleClick = useCallback((e) => {
207→    if (modelTarget === 'floor' && pastePreview?.active) return;
208→    const modelPos = getModelPos(e);
209→    tool.onDoubleClick(modelPos, e);
210→  }, [getModelPos, modelTarget, pastePreview, tool]);
211→
212→  const handleWheel = useCallback((e) => {
213→    e.preventDefault();
214→    const rect = svgRef.current.getBoundingClientRect();
215→    const mouseX = e.clientX - rect.left;
216→    const mouseY = e.clientY - rect.top;
217→
218→    const direction = e.deltaY < 0 ? 1 : -1;
219→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
220→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
221→
222→    // Zoom centered on cursor
223→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
224→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
225→
226→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
227→  }, [viewport, editorDispatch]);
228→
229→  const handleResetCenterPoint = useCallback(() => {
230→    const rect = svgRef.current?.getBoundingClientRect();
231→    if (!rect) return;
232→
233→    editorDispatch({
234→      type: 'SET_VIEWPORT',
235→      viewport: {
236→        ...viewport,
237→        panX: rect.width / 2,
238→        panY: rect.height / 2,
239→      },
240→    });
241→  }, [editorDispatch, viewport]);
242→
243→  useEffect(() => {
244→    if (!statusMessage) return undefined;
245→
246→    const timer = window.setTimeout(() => {
