439→  const roofSectionReason = roofHiddenByPhase
440→    ? SECTION_VISIBILITY_REASONS.HIDDEN_BY_PHASE
441→    : roofSectionScene?.diagnostics?.roof?.reason || null;
442→  const roofSectionMessage = getSectionVisibilityMessage('roof', roofSectionReason);
443→  const trussSectionScene = useMemo(() => {
444→    if (modelTarget !== 'truss' || viewMode !== 'section_view' || !filteredFloor) return null;
445→    const cuts = filteredFloor.sectionCuts || [];
